+                .map_err(|e| FcpError::Internal {
+                    message: e.to_string(),
+                })?
+            }
+
+            OP_LIST_RESOURCES => {
+                let subscription_id = Self::require_str(&req.input, "subscription_id")?;
+                let resource_group = Self::require_str(&req.input, "resource_group")?;
+                serde_json::to_value(
+                    client
+                        .list_resources(subscription_id, resource_group)
