+                .map_err(|e| FcpError::Internal {
+                    message: e.to_string(),
+                })?
+            }
+
+            OP_KEYVAULT_GET_SECRET => {
+                let vault_name = Self::require_str(&req.input, "vault_name")?;
+                let secret_name = Self::require_str(&req.input, "secret_name")?;
+                let vault_base_url = req
